27 +
28 +/**
29 + * @author <a href="mailto:mposolda@redhat.com">Marek Posolda</a>
30 + */
31 +public class DefaultTokenContextEncoderProvider implements TokenContextEncoderProvider {
32 +
33 +    public static final String UNKNOWN = "na";
34 +
35 +    private final KeycloakSession session;
36 +    private final DefaultTokenContextEncoderProviderFactory factory;
37 +
38 +    public DefaultTokenContextEncoderProvider(KeycloakSession session,
39 +                                              DefaultTokenContextEncoderProviderFactory factory) {
40 +        this.session = session;
41 +        this.factory = factory;
42 +    }
43 +
44 +    @Override
45 +    public AccessTokenContext getTokenContextFromClientSessionContext(ClientSessionContext clientSessionContext, String rawTokenId) {
46 +        AccessTokenContext.SessionType sessionType;
47 +        UserSessionModel userSession = clientSessionContext.getClientSession().getUserSession();
48 +        if (userSession.getPersistenceState() == UserSessionModel.SessionPersistenceState.TRANSIENT) {
49 +            sessionType = AccessTokenContext.SessionType.TRANSIENT;
50 +        } else {
51 +            sessionType = userSession.isOffline() ? AccessTokenContext.SessionType.OFFLINE : AccessTokenContext.SessionType.ONLINE;
52 +        }
53 +
54 +        boolean useLightweightToken = AbstractOIDCProtocolMapper.getShouldUseLightweightToken(session);
55 +        AccessTokenContext.TokenType tokenType = useLightweightToken ? AccessTokenContext.TokenType.LIGHTWEIGHT : AccessTokenContext.TokenType.REGULAR;
56 +
57 +        String grantType = clientSessionContext.getAttribute(Constants.GRANT_TYPE, String.class);
58 +        if (grantType == null) {
59 +            grantType = UNKNOWN;
60 +        }
61 +
62 +        return new AccessTokenContext(sessionType, tokenType, grantType, rawTokenId);
63 +    }
64 +
65 +    @Override
66 +    public AccessTokenContext getTokenContextFromTokenId(String encodedTokenId) {
67 +        int indexOf = encodedTokenId.indexOf(':');
68 +        if (indexOf == -1) {
69 +            return new AccessTokenContext(AccessTokenContext.SessionType.UNKNOWN, AccessTokenContext.TokenType.UNKNOWN, UNKNOWN, encodedTokenId);
70 +        } else {
71 +            String encodedContext = encodedTokenId.substring(0, indexOf);
72 +            String rawId = encodedTokenId.substring(indexOf + 1);
73 +
74 +            if (encodedContext.length() != 6) {
75 +                throw new IllegalArgumentException("Incorrect token id: '" + encodedTokenId + "'. Expected length of 6.");
76 +            }
77 +
78 +            // First 2 chars are "sessionType", next 2 chars "tokenType", last 2 chars "grantType"
79 +            String stShortcut = encodedContext.substring(0, 2);
80 +            String ttShortcut = encodedContext.substring(2, 4);
81 +            String gtShortcut = encodedContext.substring(4, 6);
82 +
83 +            AccessTokenContext.SessionType st = factory.getSessionTypeByShortcut(stShortcut);
84 +            if (st == null) {
85 +                throw new IllegalArgumentException("Incorrect token id: " + encodedTokenId + ". Unknown value '" + stShortcut + "' for session type");
86 +            }
87 +            AccessTokenContext.TokenType tt = factory.getTokenTypeByShortcut(ttShortcut);
88 +            if (tt == null) {
89 +                throw new IllegalArgumentException("Incorrect token id: " + encodedTokenId + ". Unknown value '" + ttShortcut + "' for token type");
90 +            }
91 +            String gt = factory.getGrantTypeByShortcut(gtShortcut);
92 +            if (gt == null) {
93 +                throw new IllegalArgumentException("Incorrect token id: " + encodedTokenId + ". Unknown value '" + gtShortcut + "' for grant type");
94 +            }
95 +
96 +            return new AccessTokenContext(st, tt, gt, rawId);
97 +        }
98 +    }
99 +
100 +    @Override
101 +    public String encodeTokenId(AccessTokenContext tokenContext) {
102 +        if (tokenContext.getSessionType() == AccessTokenContext.SessionType.UNKNOWN) {
103 +            throw new IllegalStateException("Cannot encode token with unknown sessionType");
104 +        }
105 +        if (tokenContext.getTokenType() == AccessTokenContext.TokenType.UNKNOWN) {
106 +            throw new IllegalStateException("Cannot encode token with unknown tokenType");
107 +        }
108 +
109 +        String grantShort = factory.getShortcutByGrantType(tokenContext.getGrantType());
110 +        if (grantShort == null) {
111 +            throw new IllegalStateException("Cannot encode token with unknown grantType: " + tokenContext.getGrantType());
112 +        }
113 +
114 +        return tokenContext.getSessionType().getShortcut() +
115 +                tokenContext.getTokenType().getShortcut() +
116 +                grantShort +
117 +                ':' + tokenContext.getRawTokenId();
118 +    }
119 +
120 +    @Override
121 +    public void close() {
122 +
123 +    }
124 +}"},{"filename":"services/src/main/java/org/keycloak/protocol/oidc/encode/DefaultTokenContextEncoderProviderFactory.java","patchWithLinesStr":"## file: 'services/src/main/java/org/keycloak/protocol/oidc/encode/DefaultTokenContextEncoderProviderFactory.java'

