35 + */
36 +public class DefaultTokenContextEncoderProviderFactory implements TokenContextEncoderProviderFactory {
37 +
38 +    private KeycloakSessionFactory sessionFactory;
39 +    private Map<String, AccessTokenContext.SessionType> sessionTypesByShortcut;
40 +    private Map<String, AccessTokenContext.TokenType> tokenTypesByShortcut;
41 +    Map<String, String> grantsByShortcuts;
42 +    Map<String, String> grantsToShortcuts;
43 +
44 +    @Override
45 +    public TokenContextEncoderProvider create(KeycloakSession session) {
46 +        return new DefaultTokenContextEncoderProvider(session, this);
47 +    }
48 +
49 +    @Override
50 +    public void init(Config.Scope config) {
51 +        sessionTypesByShortcut = new HashMap<>();
52 +        for (AccessTokenContext.SessionType st : AccessTokenContext.SessionType.values()) {
53 +            sessionTypesByShortcut.put(st.getShortcut(), st);
54 +        }
55 +        sessionTypesByShortcut = Collections.unmodifiableMap(sessionTypesByShortcut);
56 +
57 +        tokenTypesByShortcut = new HashMap<>();
58 +        for (AccessTokenContext.TokenType tt : AccessTokenContext.TokenType.values()) {
59 +            tokenTypesByShortcut.put(tt.getShortcut(), tt);
60 +        }
61 +        tokenTypesByShortcut = Collections.unmodifiableMap(tokenTypesByShortcut);
62 +    }
63 +
64 +    @Override
65 +    public void postInit(KeycloakSessionFactory factory) {
66 +        this.sessionFactory = factory;
67 +        grantsByShortcuts = new ConcurrentHashMap<>();
68 +        grantsToShortcuts = new ConcurrentHashMap<>();
69 +
70 +        factory.getProviderFactoriesStream(OAuth2GrantType.class)
71 +                .forEach((factory1) -> {
72 +                    OAuth2GrantTypeFactory gtf = (OAuth2GrantTypeFactory) factory1;
73 +                    String grantName = gtf.getId();
74 +                    String grantShortcut = gtf.getShortcut();
75 +                    grantsByShortcuts.put(grantShortcut, grantName);
76 +                    grantsToShortcuts.put(grantName, grantShortcut);
77 +                });
78 +        grantsByShortcuts.put(DefaultTokenContextEncoderProvider.UNKNOWN, DefaultTokenContextEncoderProvider.UNKNOWN);
79 +        grantsToShortcuts.put(DefaultTokenContextEncoderProvider.UNKNOWN, DefaultTokenContextEncoderProvider.UNKNOWN);
80 +
81 +        // Validation if there are not duplicated shortcuts (for example when introducing new grant impl...)
82 +        if (grantsByShortcuts.size() != grantsToShortcuts.size()) {
83 +            throw new IllegalStateException("Different lengths of maps. grantsByShortcuts.size=" + grantsByShortcuts.size() + ", grantsToShortcuts.size=" + grantsToShortcuts.size() +
84 +                    ". Make sure that there is no OAuth2GrantType implementation with same ID or shortcut like other grants");
85 +        }
86 +    }
87 +
88 +    @Override
89 +    public void close() {
90 +
91 +    }
92 +
93 +    @Override
94 +    public String getId() {
95 +        return "default";
96 +    }
97 +
98 +    protected AccessTokenContext.SessionType getSessionTypeByShortcut(String sessionTypeShortcut) {
99 +        return sessionTypesByShortcut.get(sessionTypeShortcut);
100 +    }
101 +
102 +    protected AccessTokenContext.TokenType getTokenTypeByShortcut(String tokenTypeShortcut) {
103 +        return tokenTypesByShortcut.get(tokenTypeShortcut);
104 +    }
105 +
106 +    protected String getShortcutByGrantType(String grantType) {
107 +        String grantShortcut = grantsToShortcuts.get(grantType);
108 +        if (grantShortcut == null) {
109 +            // Refresh maps in case new grant type was deployed
110 +            OAuth2GrantTypeFactory factory = (OAuth2GrantTypeFactory) sessionFactory.getProviderFactory(OAuth2GrantType.class, grantType);
111 +            if (factory != null) {
112 +                String shortcut = factory.getShortcut();
113 +                grantsByShortcuts.put(shortcut, grantType);
114 +                grantsToShortcuts.put(grantType, shortcut);
115 +            }
116 +            grantShortcut = grantsToShortcuts.get(grantType);
117 +        }
118 +        return grantShortcut;
119 +    }
120 +
121 +    protected String getGrantTypeByShortcut(String shortcut) {
122 +        String grantType = grantsByShortcuts.get(shortcut);
123 +        if (grantType == null) {
124 +            // Refresh maps in case new grant type was deployed
125 +            sessionFactory.getProviderFactoriesStream(OAuth2GrantType.class)
126 +                    .map(fct -> (OAuth2GrantTypeFactory) fct)
127 +                    .filter(fct -> shortcut.equals(fct.getShortcut()))
128 +                    .map(OAuth2GrantTypeFactory::getId)
129 +                    .findFirst()
130 +                    .ifPresent(newGrantType -> {
131 +                        grantsByShortcuts.put(shortcut, newGrantType);
132 +                        grantsToShortcuts.put(newGrantType, shortcut);
133 +                    });
134 +            grantType = grantsByShortcuts.get(shortcut);
135 +        }
136 +        return grantType;
137 +    }
